import java.util.*;
import java.util.function.Predicate;

public class SecurityFilterChain {

    public record Request(String path, String token, String method) {}
    public record FilterResult(boolean passed, String reason) {}

    private final List<Map.Entry<String, Predicate<Request>>> filters = new ArrayList<>();

    public void addFilter(String filterName, Predicate<Request> check) {
        filters.add(Map.entry(filterName, check));
    }

    public FilterResult process(Request request) {
        // Apply each filter in order
        // Return first FilterResult that fails (passed=false)
        // Return passed=true if all filters pass
        return new FilterResult(true, "OK");
    }

    public static void main(String[] args) {
        SecurityFilterChain chain = new SecurityFilterChain();

        // Filter 1: reject requests without a token
        chain.addFilter("AuthenticationFilter",
            req -> req.token() != null && !req.token().isBlank());

        // Filter 2: only allow GET to /public paths
        chain.addFilter("AuthorizationFilter",
            req -> req.path().startsWith("/public") || req.token().startsWith("ADMIN"));

        FilterResult r1 = chain.process(new Request("/api/data", "ADMIN-xyz", "GET"));
        System.out.println("Admin access: " + r1.passed());

        FilterResult r2 = chain.process(new Request("/api/data", null, "GET"));
        System.out.println("No token: " + r2.passed() + " (" + r2.reason() + ")");

        FilterResult r3 = chain.process(new Request("/api/secret", "user-token", "GET"));
        System.out.println("User restricted: " + r3.passed());
    }
}

import java.util.*;

public class SecurityConfigBuilder {

    private final List<String> permitAllPatterns = new ArrayList<>();
    private final List<String> authenticatedPatterns = new ArrayList<>();
    private boolean csrfEnabled = true;
    private String loginPage = "/login";

    public SecurityConfigBuilder permitAll(String... patterns) {
        permitAllPatterns.addAll(List.of(patterns));
        return this;
    }

    public SecurityConfigBuilder requireAuthentication(String... patterns) {
        authenticatedPatterns.addAll(List.of(patterns));
        return this;
    }

    public SecurityConfigBuilder disableCsrf() {
        csrfEnabled = false;
        return this;
    }

    public SecurityConfigBuilder loginPage(String path) {
        this.loginPage = path;
        return this;
    }

    public boolean isAccessible(String path, boolean authenticated) {
        // Return true if: path matches a permitAll pattern OR (authenticated AND matches requireAuthentication)
        // Wildcard support: pattern ending with /** matches any sub-path
        return false;
    }

    public static void main(String[] args) {
        SecurityConfigBuilder config = new SecurityConfigBuilder()
            .permitAll("/login", "/register", "/public/**")
            .requireAuthentication("/api/**", "/admin/**")
            .disableCsrf();

        System.out.println(config.isAccessible("/login", false));        // true
        System.out.println(config.isAccessible("/public/home", false));  // true
        System.out.println(config.isAccessible("/api/users", false));    // false
        System.out.println(config.isAccessible("/api/users", true));     // true
    }
}

import java.util.*;

public class CsrfTokenValidator {

    private final Map<String, String> sessionTokens = new HashMap<>();
    private static final Set<String> SAFE_METHODS = Set.of("GET", "HEAD", "OPTIONS");

    public String generateToken(String sessionId) {
        // Generate and store a token for the session, return it
        String token = UUID.randomUUID().toString();
        sessionTokens.put(sessionId, token);
        return token;
    }

    public boolean validate(String sessionId, String method, String submittedToken) {
        // Safe methods (GET, HEAD, OPTIONS) always pass
        // For other methods, the submittedToken must match the stored session token
        return false;
    }

    public void invalidateSession(String sessionId) {
        sessionTokens.remove(sessionId);
    }

    public static void main(String[] args) {
        CsrfTokenValidator validator = new CsrfTokenValidator();

        String token = validator.generateToken("session-1");
        System.out.println("GET allowed: " + validator.validate("session-1", "GET", null));
        System.out.println("POST with valid token: " + validator.validate("session-1", "POST", token));
        System.out.println("POST with bad token: " + validator.validate("session-1", "POST", "hacked"));
        System.out.println("POST with no session: " + validator.validate("unknown", "POST", token));
    }
}
